vulnerabilities.fix:
`event.color` 값을 허용 가능한 색상 형식(예: 헥스 코드 `#RRGGBB`, `rgb()`, `hsl()` 또는 미리 정의된 안전한 색상 이름 목록)으로 검증해야 합니다. 이 컴포넌트 내부에서 간단한 정규식을 사용하여 유효성을 검사하고, 유효하지 않은 값은 기본 색상으로 대체하거나 렌더링하지 않도록 수정할 수 있습니다.

**수정 예시:**
```typescript
// 안전한 색상 값인지 확인하는 유틸리티 함수
const isValidColor = (color: string): boolean => {
  const hexRegex = /^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/;
  const rgbRegex = /^rgb\(\s*\d{1,3}\s*,\s*\d{1,3}\s*,\s*\d{1,3}\s*\)$/;
  const rgbaRegex = /^rgba\(\s*\d{1,3}\s*,\s*\d{1,3}\s*,\s*\d{1,3}\s*,\s*(0?\.\d+|1)\s*\)$/;
  const hslRegex = /^hsl\(\s*\d{1,3}\s*,\s*\d{1,3}%\s*,\s*\d{1,3}%\s*\)$/;
  const hslaRegex = /^hsla\(\s*\d{1,3}\s*,\s*\d{1,3}%\s*,\s*\d{1,3}%\s*,\s*(0?\.\d+|1)\s*\)$/;
  // 추가적으로 허용할 CSS 색상 이름 목록을 정의할 수 있습니다.
  const namedColors = ['red', 'blue', 'green', 'black', 'white', 'transparent', 'inherit', 'initial', 'unset'];

  return (
    hexRegex.test(color) ||
    rgbRegex.test(color) ||
    rgbaRegex.test(color) ||
    hslRegex.test(color) ||
    hslaRegex.test(color) ||
    namedColors.includes(color.toLowerCase())
  );
};

// 렌더링 부분 수정
const renderEventRow = (key: string, event: Event) => (
  <div
    key={key}
    onClick={() => toggleEvent(key)}
    className={`flex cursor-pointer items-center gap-3 rounded-lg border px-3 py-2 transition-colors ${
      selectedIds.has(key) ? 'border-primary bg-primary/10' : 'border-border/50 hover:bg-card-hover'
    }`}
  >
    <input
      type="checkbox"
      checked={selectedIds.has(key)}
      onChange={() => toggleEvent(key)}
      onClick={(e) => e.stopPropagation()}
      className="h-4 w-4 shrink-0 accent-primary"
    />
    <div
      className="h-3 w-3 shrink-0 rounded-full"
      style={{ backgroundColor: isValidColor(event.color) ? event.color : '#9ca3af' }} // 유효하지 않으면 회색 기본값 사용
    />
    {/* ... 나머지 코드 ... */}
  </div>
);
```
